export const getFlagsByContinent = (continent: string): Flag[] => {
  return flags.filter(f => f.continent === continent);
};

export const getFlagById = (id: string): Flag | undefined => {
  return flags.find(f => f.id === id);
};

export const getRandomFlags = (count: number, excludeId?: string): Flag[] => {
  const pool = excludeId ? flags.filter(f => f.id !== excludeId) : [...flags];
  const shuffled = pool.sort(() => Math.random() - 0.5);
  return shuffled.slice(0, count);
};
